// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

// Shipment API endpoints
var shipments = app.MapGroup("api/shipments").RequireAuthorization();

shipments.MapGet("/", async (ApplicationDbContext db) =>
    await db.Shipments.OrderByDescending(s => s.ShippedDate).Select(s => s.ToDto()).ToListAsync());

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment.ToDto());
}).AllowAnonymous();

shipments.MapPut("/{id}/status", async (int id, ShipmentStatus newStatus, ApplicationDbContext db) =>
{
    var shipment = await db.Shipments.FindAsync(id);
    if (shipment is null) return Results.NotFound();

    shipment.Status = newStatus;
    if (newStatus == ShipmentStatus.Delivered)
        shipment.ActualDelivery = DateTime.UtcNow;

    await db.SaveChangesAsync();
    return Results.Ok(shipment.ToDto());
});

// Ensure database is created with seed data
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    db.Database.Migrate();
}

app.Run();

