@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<div class="container">
    <h2 class="mb-4">Track Your Shipment</h2>

    <div class="row mb-4">
        <div class="col-md-8">
            <div class="input-group">
                <input type="text" class="form-control form-control-lg" placeholder="Enter tracking number (e.g., TRK-001-2026)"
                       @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary btn-lg" @onclick="TrackShipment" disabled="@isLoading">
                    @if (isLoading)
                    {
                        <span class="spinner-border spinner-border-sm me-2" role="status"></span>
                    }
                    Track
                </button>
            </div>
        </div>
    </div>

    @if (searched && shipment is null)
    {
        <div class="alert alert-warning">
            <strong>Not found.</strong> No shipment matches tracking number "<strong>@searchedNumber</strong>". Please check the number and try again.
        </div>
    }

    @if (shipment is not null)
    {
        <div class="card shadow-sm">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h4 class="mb-0">@shipment.TrackingNumber</h4>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6">
                        <dl>
                            <dt>Description</dt>
                            <dd>@shipment.Description</dd>
                            <dt>Origin</dt>
                            <dd>@shipment.Origin</dd>
                            <dt>Destination</dt>
                            <dd>@shipment.Destination</dd>
                        </dl>
                    </div>
                    <div class="col-md-6">
                        <dl>
                            <dt>Shipped Date</dt>
                            <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                            <dt>Estimated Delivery</dt>
                            <dd>
                                @if (shipment.EstimatedDelivery.HasValue)
                                {
                                    @shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")
                                }
                                else
                                {
                                    <span class="text-muted">Pending</span>
                                }
                            </dd>
                            @if (shipment.ActualDelivery.HasValue)
                            {
                                <dt>Delivered On</dt>
                                <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy")</dd>
                            }
                        </dl>
                    </div>
                </div>

                <!-- Status timeline -->
                <h5 class="mt-3">Shipment Progress</h5>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(shipment.Status)" role="progressbar"
                         style="width: @GetProgressPercentage(shipment.Status)%"
                         aria-valuenow="@GetProgressPercentage(shipment.Status)" aria-valuemin="0" aria-valuemax="100">
                        @shipment.Status
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool searched;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        searched = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        isLoading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary"
    };

    private static int GetProgressPercentage(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 75,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

@page "/shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<div class="container-fluid">
    <div class="d-flex justify-content-between align-items-center mb-4">
        <h2>Dispatcher Dashboard</h2>
        <button class="btn btn-outline-primary" @onclick="LoadShipments" disabled="@isLoading">
            @if (isLoading)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Refresh
        </button>
    </div>

    <!-- Filters -->
    <div class="row mb-3 g-2">
        <div class="col-md-4">
            <input type="text" class="form-control" placeholder="Search by tracking #, destination, or description..."
                   @bind="searchFilter" @bind:event="oninput" />
        </div>
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@status</option>
                }
            </select>
        </div>
    </div>

    @if (shipments is null)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
            <p class="mt-2">Loading shipments...</p>
        </div>
    }
    else if (!FilteredShipments.Any())
    {
        <div class="alert alert-info">No shipments match your filters.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover table-striped align-middle">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Description</th>
                        <th>Origin</th>
                        <th>Destination</th>
                        <th>Status</th>
                        <th>Shipped</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var s in FilteredShipments)
                    {
                        <tr>
                            <td><code>@s.TrackingNumber</code></td>
                            <td>@s.Description</td>
                            <td>@s.Origin</td>
                            <td><strong>@s.Destination</strong></td>
                            <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
                            <td>@s.ShippedDate.ToString("MMM dd")</td>
                            <td>@(s.EstimatedDelivery?.ToString("MMM dd") ?? "—")</td>
                            <td>
                                @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Returned)
                                {
                                    <div class="btn-group btn-group-sm">
                                        <select class="form-select form-select-sm" style="width: auto;"
                                                @onchange="(e) => UpdateStatus(s, e)">
                                            <option value="" disabled selected>Update...</option>
                                            @foreach (var status in GetAvailableStatuses(s.Status))
                                            {
                                                <option value="@status">@status</option>
                                            }
                                        </select>
                                    </div>
                                }
                                else
                                {
                                    <span class="text-muted">—</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <div class="text-muted">
            Showing @FilteredShipments.Count() of @shipments.Count shipments
        </div>
    }
</div>

@code {
    private List<ShipmentDto>? shipments;
    private string searchFilter = string.Empty;
    private string statusFilter = string.Empty;
    private bool isLoading;

    private IEnumerable<ShipmentDto> FilteredShipments => shipments?.Where(s =>
    {
        var matchesSearch = string.IsNullOrWhiteSpace(searchFilter) ||
            s.TrackingNumber.Contains(searchFilter, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(searchFilter, StringComparison.OrdinalIgnoreCase) ||
            s.Description.Contains(searchFilter, StringComparison.OrdinalIgnoreCase);

        var matchesStatus = string.IsNullOrWhiteSpace(statusFilter) ||
            s.Status.ToString() == statusFilter;

        return matchesSearch && matchesStatus;
    }) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        isLoading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync();
        isLoading = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is string val && Enum.TryParse<ShipmentStatus>(val, out var newStatus))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                var index = shipments!.FindIndex(s => s.Id == shipment.Id);
                if (index >= 0)
                    shipments[index] = updated;
            }
        }
    }

    private static ShipmentStatus[] GetAvailableStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Delayed],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Delayed],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Delayed],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Delayed],
        ShipmentStatus.Delayed => [ShipmentStatus.InTransit, ShipmentStatus.Returned],
        _ => []
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}

