@code {
    private List<ShipmentDto>? shipments;
    private string searchFilter = string.Empty;
    private string statusFilter = string.Empty;
    private bool isLoading;

    private IEnumerable<ShipmentDto> FilteredShipments => shipments?.Where(s =>
    {
        var matchesSearch = string.IsNullOrWhiteSpace(searchFilter) ||
            s.TrackingNumber.Contains(searchFilter, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(searchFilter, StringComparison.OrdinalIgnoreCase) ||
            s.Description.Contains(searchFilter, StringComparison.OrdinalIgnoreCase);

        var matchesStatus = string.IsNullOrWhiteSpace(statusFilter) ||
            s.Status.ToString() == statusFilter;

        return matchesSearch && matchesStatus;
    }) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        isLoading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync();
        isLoading = false;
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is string val && Enum.TryParse<ShipmentStatus>(val, out var newStatus))
        {
            var updated = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                var index = shipments!.FindIndex(s => s.Id == shipment.Id);
                if (index >= 0)
                    shipments[index] = updated;
            }
        }
    }

    private static ShipmentStatus[] GetAvailableStatuses(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Delayed],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Delayed],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Delayed],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Delayed],
        ShipmentStatus.Delayed => [ShipmentStatus.InTransit, ShipmentStatus.Returned],
        _ => []
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Returned => "bg-dark",
        _ => "bg-secondary"
    };
}
